96	function createFixedWindowRateLimiter(params: {
97	  windowMs: number;
98	  maxRequests: number;
99	  maxTrackedKeys: number;
100	}): FixedWindowRateLimiter {
101	  const windowMs = Math.max(1, Math.floor(params.windowMs));
102	  const maxRequests = Math.max(1, Math.floor(params.maxRequests));
103	  const maxTrackedKeys = Math.max(1, Math.floor(params.maxTrackedKeys));
104	  const state = new Map<string, { count: number; windowStartMs: number }>();
105	
106	  const touch = (key: string, value: { count: number; windowStartMs: number }) => {
107	    state.delete(key);
108	    state.set(key, value);
109	  };
110	
111	  const prune = (nowMs: number) => {
112	    for (const [key, entry] of state) {
113	      if (nowMs - entry.windowStartMs >= windowMs) {
114	        state.delete(key);
115	      }
116	    }
117	    while (state.size > maxTrackedKeys) {
118	      const oldest = state.keys().next().value;
119	      if (!oldest) {
120	        break;
121	      }
122	      state.delete(oldest);
123	    }
124	  };
125	
126	  return {
127	    isRateLimited: (key: string, nowMs = Date.now()) => {
128	      if (!key) {
129	        return false;
130	      }
131	      prune(nowMs);
132	      const existing = state.get(key);
133	      if (!existing || nowMs - existing.windowStartMs >= windowMs) {
134	        touch(key, { count: 1, windowStartMs: nowMs });
135	        return false;
136	      }
137	      const nextCount = existing.count + 1;
138	      touch(key, { count: nextCount, windowStartMs: existing.windowStartMs });
139	      return nextCount > maxRequests;
