import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import type { ChannelMeta } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

// PulseBoard meta: defined inline because "pulseboard" is not yet in the core
// ChatChannelId union (src/channels/ids.ts). Once registered there,
// this can be replaced with getChatChannelMeta("pulseboard").
const meta: ChannelMeta = {
  id: "pulseboard",
  label: "PulseBoard",
  selectionLabel: "PulseBoard (Bulletin)",
  docsPath: "/channels/pulseboard",
  blurb: "Connect to PulseBoard bulletin messaging.",
};

export const pulseBoardPlugin = createChatChannelPlugin<PulseBoardAccount>({
  base: {
    id: "pulseboard",
    meta,
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: {
      configPrefixes: ["channels.pulseboard"],
    },

    // Config adapter: resolve accounts from the channels.pulseboard config block.
    // Stubs return empty/default values until a real PulseBoard config schema is wired up.
    config: {
      listAccountIds: (_cfg) => [],
      resolveAccount: (_cfg, _accountId): PulseBoardAccount => ({
        boardUrl: "",
        apiToken: "",
        username: "",
      }),
      isConfigured: (account) => Boolean(account.boardUrl && account.apiToken),
    },

    // Setup adapter: apply account config written by the setup wizard.
    setup: {
      applyAccountConfig: ({ cfg }) => cfg,
    },

    // Gateway adapter: open a persistent connection to the PulseBoard server.
    // Stub logs the attempt and returns a no-op stop handle.
    gateway: {
      startAccount: async ({ account, log }) => {
        log.info(`PulseBoard: connecting account to ${account.boardUrl}`);
        return { stop: () => {} };
      },
    },

    // Messaging adapter: normalise the outbound target address.
    messaging: {
      normalizeTarget: ({ to }) => to.trim(),
    },
  },

  // Outbound adapter: deliver text messages to a board or DM recipient.
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    // Stub: returns a synthetic delivery result; replace with real API call.
    sendText: async ({ to }) =>
      ({
        channel: "pulseboard",
        to,
        messageId: `pb-${Date.now()}`,
      }) as never,
  },
});

